  // ═══════════════════════════════════════════════════════
  //  Helpers
  // ═══════════════════════════════════════════════════════
  healthToClass(status) {
    switch (status) {
      case "running":
        return "running";
      case "error":
        return "error";
      case "pending":
        return "pending";
      case "disabled":
        return "disabled";
      default:
        return "idle";
    }
  }
  statusToTimelineClass(status) {
    switch (status) {
      case "success":
        return "success";
      case "failure":
      case "timeout":
        return "error";
      case "cancelled":
        return "warning";
      case "pending_approval":
        return "pending";
      default:
        return "running";
    }
  }
  statusToIconName(status) {
    switch (status) {
      case "success":
        return "check-circle-2";
      case "failure":
        return "x-circle";
      case "timeout":
        return "clock";
      case "pending_approval":
        return "shield-check";
      case "cancelled":
        return "square";
      default:
        return "loader-2";
    }
  }
  statusToBadgeClass(status) {
    switch (status) {
      case "success":
        return "success";
      case "failure":
        return "failure";
      case "timeout":
        return "timeout";
      case "pending_approval":
        return "pending";
      case "cancelled":
        return "cancelled";
      default:
        return "running";
    }
  }
  statusToBadgeText(status) {
    switch (status) {
      case "success":
        return "Success";
      case "failure":
        return "Failed";
      case "timeout":
        return "Timeout";
      case "pending_approval":
        return "Pending";
      case "cancelled":
        return "Cancelled";
      case "interrupted":
        return "Interrupted";
      default:
        return status;
    }
  }
  formatDuration(seconds) {
    if (seconds < 60) return `${seconds}s`;
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return s > 0 ? `${m}m ${s}s` : `${m}m`;
  }
