  renderMcpPage(container) {
    const page = container.createDiv({ cls: "af-agents-page" });
    const toolbar = page.createDiv({ cls: "af-agents-toolbar" });
    toolbar.createDiv({ cls: "af-page-title", text: "MCP Servers" });
    toolbar.createDiv({ cls: "af-toolbar-spacer" });
    const refreshBtn = toolbar.createEl("button", { cls: "af-btn-sm" });
    createIcon(refreshBtn, "refresh-cw", "af-btn-icon");
    refreshBtn.appendText(" Refresh");
    refreshBtn.onclick = () => {
      this.plugin.mcpManager.invalidateCache();
      void this.render();
    };
    const cachedServers = this.plugin.mcpManager.getCachedServers();
    if (cachedServers === null) {
      const progressContainer = page.createDiv({ cls: "af-mcp-progress" });
      const progressHeader = progressContainer.createDiv({ cls: "af-mcp-progress-header" });
      const spinner = progressHeader.createDiv({ cls: "af-mcp-spinner" });
      for (let i = 0; i < 3; i++) spinner.createSpan();
      const progressLabel = progressHeader.createSpan({
        cls: "af-mcp-progress-label",
        text: "Discovering MCP servers\u2026"
      });
      const progressBar = progressContainer.createDiv({ cls: "af-mcp-progress-bar" });
      const progressFill = progressBar.createDiv({ cls: "af-mcp-progress-fill" });
      progressFill.style.width = "15%";
      const progressDetail = progressContainer.createDiv({
        cls: "af-mcp-progress-detail",
        text: "Scanning for configured servers\u2026"
      });
      const unsub = this.plugin.mcpManager.onProgress((update) => {
        switch (update.phase) {
          case "list":
            progressLabel.setText("Scanning servers\u2026");
            progressDetail.setText(update.message);
            progressFill.style.width = "20%";
            break;
          case "details":
            progressLabel.setText(`Checking server ${update.current}/${update.total}\u2026`);
            progressDetail.setText(update.serverName);
            progressFill.style.width = `${20 + update.current / update.total * 30}%`;
            break;
          case "tools":
            progressLabel.setText("Discovering tools\u2026");
            progressDetail.setText(update.message);
            progressFill.style.width = "60%";
            progressFill.addClass("af-mcp-progress-fill-slow");
            break;
          case "done":
            progressFill.style.width = "100%";
            progressLabel.setText("Done");
            progressDetail.setText(
              `${update.serverCount} server${update.serverCount !== 1 ? "s" : ""}, ${update.toolCount} tool${update.toolCount !== 1 ? "s" : ""} discovered`
            );
            break;
        }
      });
      this.streamingUnsubscribes.push(unsub);
      void this.plugin.mcpManager.getServers().then(() => void this.render()).catch(() => void this.render());
      return;
    }
    if (cachedServers.length === 0) {
      this.renderEmptyState(page, "plug", "No MCP servers found", "Configure servers with 'claude mcp add'");
      return;
    }
    const grid = page.createDiv({ cls: "af-agents-grid" });
    for (const server of cachedServers) {
      this.renderMcpCard(grid, server);
    }
  }
